#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int sumSubarrayMin(vector<int>& arr) {
        const int MOD = 1e9 + 7;
        stack<pair<int, int>> stk;
        long long res = 0;
        for (int i = 0; i < arr.size(); ++i) {
            while (!stk.empty() && stk.top().first > arr[i]) {
                int val = stk.top().first;
                int cnt = stk.top().second;
                stk.pop();
                int left_cnt = stk.empty() ? 0 : stk.top().second;
                res += (long long)(cnt - left_cnt) * (i - cnt) * val % MOD;
                res %= MOD;
            }
            stk.emplace(arr[i], i + 1);
        }
        while (!stk.empty()) {
            int val = stk.top().first;
            int cnt = stk.top().second;
            stk.pop();
            int left_cnt = stk.empty() ? 0 : stk.top().second;
            res += (long long)(cnt - left_cnt) * (arr.size() - cnt) * val % MOD;
            res %= MOD;
        }
        return res % MOD;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution sol;
    int ans = sol.sumSubarrayMin(arr);
    cout << ans << '\n';
    return 0;
}
